class Solution {
    public String concatHex36(int n) {
        String hex = Integer.toHexString(n * n).toUpperCase();
        StringBuilder hexatrigesimal = new StringBuilder();
        long num = (long) n * n * n;
        while (num > 0) {
            long remainder = num % 36;
            if (remainder < 10) {
                hexatrigesimal.insert(0, remainder);
            } else {
                hexatrigesimal.insert(0, (char) ('A' + remainder - 10));
            }
            num /= 36;
        }
        return hex + hexatrigesimal.toString();
    }
}
